INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00427', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '對於移入違規舍受刑人生活處遇管制，下列敘述何者錯誤？', '["應停止作業", "穿著指定之服制", "禁止持有及使用電器物品，包括電動刮鬍刀", "禁止吸菸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00428', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄行刑法接見之規定，下列敘述何者正確？', '["受刑人之接見，除依受刑人意願拒絕外，監獄不得限制或禁止。接見次數每天1次", "監獄應於國定例假日或其他休息日辦理接見", "受刑人與其律師、辯護人接見，除有事實上困難外，不限制接見次數及時間", "接見，每次僅限2人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00429', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第96條規定，以書面提起申訴者，應填具申訴書，由申訴人簽名或捺印，下列何者非 應載明之事項？', '["申訴人之罪名、刑期", "申訴事實及發生時間", "申訴理由", "申訴年、月、日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00430', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人得向監獄申請准其使用電話或其他通訊方式接見，下列有關監獄辦理使用通訊設備接見之具體 措施，依矯正法令規定，何者錯誤？', '["受刑人使用通訊設備接見，得每月2次，但以其最近親屬有生命危險為由辦理時，不計入前述次數", "使用通訊設備接見，每次以30分鐘為限。但機關認有必要時，得調整加減之", "接見所產生之通訊費用，得由被許可接見者負擔，其無力負擔且機關認為適當時，應由機關支付之", "被許可接見者規避監獄依規定所為之監看或聽聞，監獄得中止接見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00431', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人接見或發信，監獄應保障其無障礙權益，並採取適當措施為合理調整，下列敘述何者錯誤？', '["視覺障礙受刑人發信，得使用點字或其他適當輔助方式", "受刑人因患病或於管理教化上之必要，監獄得准受刑人於適當處所接見", "受刑人不識字或因故不能書寫信件者，由監獄逕行指定受刑人協助代為書寫", "聽覺障礙受刑人接見，得使用手語或其他適當輔助方式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00432', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄行刑法申訴之規定，下列敘述何者錯誤？', '["受刑人不服監獄所為影響其個人權益之處分或管理措施，得向監獄提起申訴", "受刑人因監獄對其依本法請求之事件，拒絕其請求或於1個月內不依其請求作成決定，認為其權利 或法律上利益受損害，得向監獄提起申訴", "受刑人因監獄行刑之公法上原因發生之財產給付爭議，得向監獄提起申訴", "受刑人提起申訴，得委任律師為代理人行之，並應向監獄提出委任狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00433', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關行刑累進處遇條例各級受刑人接見及寄發書信次數之規定，下列敘述何者錯誤？', '["第四級受刑人每星期1次", "第三級受刑人每星期1次或2次", "第二級受刑人每4日1次", "第一級受刑人不受限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00434', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄受刑人釋放，下列敘述何者錯誤？', '["執行期滿者之釋放，應於其刑期終了之次日午前釋放之", "核准假釋者，應於保護管束命令送交監獄後24小時內釋放之。但有特殊事由者，得於指定日期辦 理釋放", "受赦免者，應於公文到達後至遲24小時內釋放之", "釋放後之保護扶助事項，除法規另有規定外，應於受刑人執行期滿出監前或提報假釋前先行調查， 必要時，得於釋放前再予覆查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00435', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關假釋與縮短刑期之比較，下列敘述何者錯誤？', '["二者均在鼓勵受刑人保持善行，改善更生", "假釋適用有期徒刑及無期徒刑受刑人，縮短刑期僅適用於符合法定條件之有期徒刑受刑人", "假釋僅適用於二級以上受刑人，縮短刑期僅適用於一般監獄及外役監獄三級以上之受刑人", "假釋受刑人釋放後應交付保護管束，縮短刑期提前出獄之受刑人無交付保護管束之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00436', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '為維護監獄秩序及安全，防止違禁物品流入，受刑人入監時，應檢查其身體、衣類及攜帶之物品，下 列敘述何者錯誤？', '["必要時，得採集其尿液檢驗", "為辨識受刑人身分，應照相、採取指紋或記錄其他身體特徵，並得運用科技設備輔助之", "有事實足認受刑人有夾藏違禁物品或有其他危害監獄秩序及安全之虞，仍不得為侵入性之檢查", "如須脫衣檢查時，應於有遮蔽之處所為之，並注意維護受刑人隱私及尊嚴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
